#!/usr/bin/env node
/**
 * Builds paste-ready copies of each migration for the Supabase SQL editor.
 *
 *   node db/tools/manual-bundle.mjs
 *
 * Writes db/migrations/_manual/<name>.sql — each one is the migration
 * wrapped in BEGIN/COMMIT plus the matching schema_migrations INSERT, so a
 * manual paste records itself exactly as the automated runner would. That
 * keeps `npm run db:migrate` accurate afterwards: it sees these as applied
 * and does not try to re-run them.
 *
 * The checksums are computed from the real migration files at build time,
 * so this must be re-run whenever a migration changes. _manual/ is
 * generated output and is gitignored.
 */
import { readFileSync, readdirSync, writeFileSync, mkdirSync } from 'node:fs';
import { createHash } from 'node:crypto';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const MIGRATIONS_DIR = join(dirname(fileURLToPath(import.meta.url)), '..', 'migrations');
const OUT_DIR = join(MIGRATIONS_DIR, '_manual');

mkdirSync(OUT_DIR, { recursive: true });

const files = readdirSync(MIGRATIONS_DIR)
  .filter((f) => f.endsWith('.sql'))
  .sort();

for (const name of files) {
  const sql = readFileSync(join(MIGRATIONS_DIR, name), 'utf8');
  const checksum = createHash('sha256').update(sql).digest('hex');

  const wrapped = `-- =====================================================================
-- PASTE-READY: ${name}
-- Generated by db/tools/manual-bundle.mjs — do not edit.
-- Source of truth is db/migrations/${name}.
--
-- Paste this whole file into the Supabase SQL editor and Run. It is
-- wrapped in a transaction: on any error nothing is applied and nothing
-- is recorded, so you can fix and re-run from a clean state.
-- =====================================================================

BEGIN;

CREATE TABLE IF NOT EXISTS schema_migrations (
  name        text PRIMARY KEY,
  checksum    text NOT NULL,
  applied_at  timestamptz NOT NULL DEFAULT now()
);

-- Refuse to apply twice. If this migration is already recorded, the
-- exception aborts the transaction and nothing below runs again.
DO $migration_guard$
BEGIN
  IF EXISTS (SELECT 1 FROM schema_migrations WHERE name = '${name}') THEN
    RAISE EXCEPTION 'Migration ${name} is already applied — nothing to do.';
  END IF;
END
$migration_guard$;

${sql}

INSERT INTO schema_migrations (name, checksum) VALUES ('${name}', '${checksum}');

COMMIT;
`;

  writeFileSync(join(OUT_DIR, name), wrapped);
  console.log(`  ${name}  (sha256 ${checksum.slice(0, 12)}…)`);
}

console.log(`\nWrote ${files.length} file(s) to db/migrations/_manual/`);
